import java.util.List;

import org.springframework.data.domain.Sort;
import org.springframework.data.mongodb.core.MongoTemplate;
import org.springframework.data.mongodb.core.aggregation.Aggregation;
import org.springframework.data.mongodb.core.aggregation.AggregationResults;
import org.springframework.data.mongodb.core.aggregation.GroupOperation;
import org.springframework.data.mongodb.core.aggregation.SortOperation;
import org.springframework.data.mongodb.core.query.Criteria;
import org.springframework.data.mongodb.core.query.Query;

class MongoQueryEntrypoint {

    private final MongoTemplate mongoTemplate;

    MongoQueryEntrypoint(MongoTemplate mongoTemplate) {
        this.mongoTemplate = mongoTemplate;
    }

    List<OrderLine> query1() {
        LocalDate from = LocalDate.of(2014, 12, 20);
        LocalDate to = LocalDate.of(2014, 12, 31);
        Query query = Query.query(Criteria.where("pickingCompletedWhen").gte(from).lte(to));
        return mongoTemplate.find(query, OrderLine.class);
    }

    List<Order> query2() {
        Query query = Query.query(Criteria.where("customerId").is(1));
        return mongoTemplate.find(query, Order.class);
    }

    List<GroupResult> query3() {
        GroupOperation groupByTaxRate = Aggregation.group("taxRate").count().as("count");
        SortOperation sortByCountDesc = Aggregation.sort(Sort.Direction.DESC, "count");
        Aggregation aggregation = Aggregation.newAggregation(groupByTaxRate, sortByCountDesc);
        AggregationResults<GroupResult> results = mongoTemplate.aggregate(aggregation, "orderLines", GroupResult.class);
        return results.getMappedResults();
    }

    List<OrderLine> query4() {
        Query query = new Query().with(Sort.by(Sort.Direction.DESC, "quantity")).limit(50);
        return mongoTemplate.find(query, OrderLine.class);
    }

    List<OrderLineProjection> query5() {
        Query query = new Query();
        query.fields().include("orderLineId").include("quantity");
        return mongoTemplate.find(query, OrderLineProjection.class, "orderLines");
    }

    static class GroupResult {
        private String taxRate;
        private long count;

        public String getTaxRate() {
            return taxRate;
        }

        public void setTaxRate(String taxRate) {
            this.taxRate = taxRate;
        }

        public long getCount() {
            return count;
        }

        public void setCount(long count) {
            this.count = count;
        }
    }

    interface OrderLineProjection {
        Integer getOrderLineId();
        Integer getQuantity();
    }
}"
